/**
 * Main App Component
 * Root component that manages the overall application state
 */

import React, { useState, useEffect } from "react";
import axios from "axios";
import Dashboard from "./components/Dashboard";
import AddMedication from "./components/AddMedication";

// API Base URL - Change this if backend is on different port
const API_URL = "http://localhost:5000/api";

// Demo user ID (in a real app, this would come from authentication)
// For demo purposes, we'll use a fixed user ID
const DEMO_USER_ID = "65a1b2c3d4e5f6a7b8c9d0e1";

function App() {
  // State to hold all medications
  const [medications, setMedications] = useState([]);
  // Loading state for API calls
  const [loading, setLoading] = useState(true);
  // Error state for API errors
  const [error, setError] = useState(null);
  // State to control the Add Medication modal
  const [showAddForm, setShowAddForm] = useState(false);

  /**
   * Fetch all medications from the API
   * Called on component mount and after adding new medication
   */
  const fetchMedications = async () => {
    try {
      setLoading(true);
      setError(null);

      const response = await axios.get(
        `${API_URL}/medications/${DEMO_USER_ID}`,
      );

      if (response.data.success) {
        setMedications(response.data.data);
      }
    } catch (err) {
      console.error("Error fetching medications:", err);
      // If API fails, show demo data for presentation purposes
      setMedications(getDemoData());
      setError("Using demo data - Backend server not connected");
    } finally {
      setLoading(false);
    }
  };

  /**
   * Add a new medication
   * @param {Object} medicationData - The medication data from the form
   */
  const addMedication = async (medicationData) => {
    try {
      const response = await axios.post(`${API_URL}/medications`, {
        ...medicationData,
        userId: DEMO_USER_ID,
      });

      if (response.data.success) {
        // Refresh the medications list
        fetchMedications();
        setShowAddForm(false);
        return { success: true };
      }
    } catch (err) {
      console.error("Error adding medication:", err);
      // For demo: add to local state if API fails
      const newMed = createDemoMedication(medicationData);
      setMedications((prev) => [newMed, ...prev]);
      setShowAddForm(false);
      return { success: true, demo: true };
    }
  };

  /**
   * Delete a medication
   * @param {string} id - The medication ID to delete
   */
  const deleteMedication = async (id) => {
    try {
      await axios.delete(`${API_URL}/medications/${id}`);
      // Refresh the medications list
      fetchMedications();
    } catch (err) {
      console.error("Error deleting medication:", err);
      // For demo: remove from local state
      setMedications((prev) => prev.filter((med) => med._id !== id));
    }
  };

  /**
   * Refill a medication
   * @param {string} id - The medication ID to refill
   */
  const refillMedication = async (id, totalQuantity) => {
    try {
      await axios.put(`${API_URL}/medications/${id}/refill`, { totalQuantity });
      fetchMedications();
    } catch (err) {
      console.error("Error refilling medication:", err);
      // For demo: update local state
      setMedications((prev) =>
        prev.map((med) => {
          if (med._id === id) {
            return {
              ...med,
              totalQuantity: totalQuantity || med.totalQuantity,
              remainingStock: totalQuantity || med.totalQuantity,
              startDate: new Date().toISOString(),
              daysElapsed: 0,
              pillsConsumed: 0,
              daysRemaining: Math.floor(
                (totalQuantity || med.totalQuantity) / med.dailyDosage,
              ),
              needsRefill: false,
            };
          }
          return med;
        }),
      );
    }
  };

  // Fetch medications on component mount
  useEffect(() => {
    fetchMedications();
  }, []);

  return (
    <div className="min-h-screen bg-gradient-to-br from-blue-50 via-white to-purple-50">
      {/* Header */}
      <header className="bg-white shadow-sm border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <div className="flex items-center justify-between">
            {/* Logo and Title */}
            <div className="flex items-center space-x-3">
              <div className="bg-blue-600 p-2 rounded-lg">
                <svg
                  className="w-8 h-8 text-white"
                  fill="none"
                  stroke="currentColor"
                  viewBox="0 0 24 24"
                >
                  <path
                    strokeLinecap="round"
                    strokeLinejoin="round"
                    strokeWidth={2}
                    d="M19.428 15.428a2 2 0 00-1.022-.547l-2.387-.477a6 6 0 00-3.86.517l-.318.158a6 6 0 01-3.86.517L6.05 15.21a2 2 0 00-1.806.547M8 4h8l-1 1v5.172a2 2 0 00.586 1.414l5 5c1.26 1.26.367 3.414-1.415 3.414H4.828c-1.782 0-2.674-2.154-1.414-3.414l5-5A2 2 0 009 10.172V5L8 4z"
                  />
                </svg>
              </div>
              <div>
                <h1 className="text-2xl font-bold text-gray-900">MedTracker</h1>
                <p className="text-sm text-gray-500">
                  Medication Tracker & Refill Reminder
                </p>
              </div>
            </div>

            {/* Add Medication Button */}
            <button
              onClick={() => setShowAddForm(true)}
              className="btn-primary flex items-center space-x-2"
            >
              <svg
                className="w-5 h-5"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M12 4v16m8-8H4"
                />
              </svg>
              <span>Add Medication</span>
            </button>
          </div>
        </div>
      </header>

      {/* Main Content */}
      <main className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-8">
        {/* Error Banner */}
        {error && (
          <div className="mb-6 bg-yellow-50 border border-yellow-200 rounded-lg p-4">
            <div className="flex items-center">
              <svg
                className="w-5 h-5 text-yellow-600 mr-2"
                fill="none"
                stroke="currentColor"
                viewBox="0 0 24 24"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={2}
                  d="M12 9v2m0 4h.01m-6.938 4h13.856c1.54 0 2.502-1.667 1.732-3L13.732 4c-.77-1.333-2.694-1.333-3.464 0L3.34 16c-.77 1.333.192 3 1.732 3z"
                />
              </svg>
              <span className="text-yellow-800">{error}</span>
            </div>
          </div>
        )}

        {/* Dashboard */}
        <Dashboard
          medications={medications}
          loading={loading}
          onDelete={deleteMedication}
          onRefill={refillMedication}
        />
      </main>

      {/* Add Medication Modal */}
      {showAddForm && (
        <AddMedication
          onAdd={addMedication}
          onClose={() => setShowAddForm(false)}
        />
      )}

      {/* Footer */}
      <footer className="bg-white border-t border-gray-100 mt-auto">
        <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8 py-4">
          <p className="text-center text-gray-500 text-sm">
            © 2026 MedTracker - College Project | MERN Stack Application
          </p>
        </div>
      </footer>
    </div>
  );
}

/**
 * Generate demo data for presentation purposes
 * Used when backend is not connected
 */
function getDemoData() {
  return [
    {
      _id: "demo1",
      medicineName: "Vitamin D3",
      totalQuantity: 30,
      dailyDosage: 1,
      startDate: new Date(Date.now() - 10 * 24 * 60 * 60 * 1000).toISOString(), // 10 days ago
      remainingStock: 20,
      daysElapsed: 10,
      pillsConsumed: 10,
      daysRemaining: 20,
      refillThreshold: 5,
      needsRefill: false,
    },
    {
      _id: "demo2",
      medicineName: "Omega-3 Fish Oil",
      totalQuantity: 60,
      dailyDosage: 2,
      startDate: new Date(Date.now() - 25 * 24 * 60 * 60 * 1000).toISOString(), // 25 days ago
      remainingStock: 10,
      daysElapsed: 25,
      pillsConsumed: 50,
      daysRemaining: 5,
      refillThreshold: 10,
      needsRefill: true,
    },
    {
      _id: "demo3",
      medicineName: "Aspirin",
      totalQuantity: 100,
      dailyDosage: 1,
      startDate: new Date(Date.now() - 5 * 24 * 60 * 60 * 1000).toISOString(), // 5 days ago
      remainingStock: 95,
      daysElapsed: 5,
      pillsConsumed: 5,
      daysRemaining: 95,
      refillThreshold: 10,
      needsRefill: false,
    },
    {
      _id: "demo4",
      medicineName: "Metformin",
      totalQuantity: 30,
      dailyDosage: 2,
      startDate: new Date(Date.now() - 13 * 24 * 60 * 60 * 1000).toISOString(), // 13 days ago
      remainingStock: 4,
      daysElapsed: 13,
      pillsConsumed: 26,
      daysRemaining: 2,
      refillThreshold: 5,
      needsRefill: true,
    },
  ];
}

/**
 * Create a demo medication object from form data
 */
function createDemoMedication(data) {
  const startDate = new Date(data.startDate);
  const today = new Date();
  const daysElapsed = Math.floor((today - startDate) / (1000 * 60 * 60 * 24));
  const pillsConsumed = data.dailyDosage * daysElapsed;
  const remainingStock = Math.max(0, data.totalQuantity - pillsConsumed);

  return {
    _id: "demo_" + Date.now(),
    medicineName: data.medicineName,
    totalQuantity: data.totalQuantity,
    dailyDosage: data.dailyDosage,
    startDate: data.startDate,
    remainingStock,
    daysElapsed,
    pillsConsumed,
    daysRemaining: Math.floor(remainingStock / data.dailyDosage),
    refillThreshold: data.refillThreshold || 5,
    needsRefill: remainingStock <= (data.refillThreshold || 5),
  };
}

export default App;
